/* ── Helpers ───────────────────────────────────── */

function el(id) {
    return document.getElementById(id);
}

function fadeIn(element) {
    element.style.display = 'block';
}

function fadeOutAudio(audio, duration) {
    var steps = 20;
    var stepTime = duration / steps;
    var decrement = audio.volume / steps;
    var interval = setInterval(function () {
        audio.volume = Math.max(0, audio.volume - decrement);
        if (audio.volume <= 0) { clearInterval(interval); }
    }, stepTime);
}

function on(id, event, handler) {
    el(id).addEventListener(event, handler);
}


/* ── Audio ─────────────────────────────────────── */

function playVoiceSound(data, answerWasCorrect) {
    if (!AppStorage.getSetting('SETTING_SOUND')) { return; }

    var isOnlyPositiveSound = AppStorage.getSetting('SETTING_POSITIVE');
    if (isOnlyPositiveSound && !answerWasCorrect) { return; }

    var soundInfo = answerWasCorrect ? data.sound.answerWasCorrect : data.sound.answerWasNotCorrect;

    if (data.resetPlayedSounds) { AppStorage.resetPlayedSounds(); }
    if (soundInfo.filename) {
        var audio = new Audio();
        audio.src = audio.canPlayType('audio/ogg; codecs=vorbis')
            ? '/audio/voice/ogg/' + soundInfo.filename + '.ogg'
            : '/audio/voice/mp3/' + soundInfo.filename + '.mp3';
        audio.play();
        AppStorage.addPlayedSound(soundInfo.id);
    }
}

function playEndMusic() {
    if (!AppStorage.getSetting('SETTING_SOUND')) { return; }
    var fileIndex = AppStorage.getNextEndSoundIndex();
    var audio = new Audio();
    audio.src = audio.canPlayType('audio/ogg; codecs=vorbis')
        ? '/audio/ending/ogg/end_' + fileIndex + '.ogg'
        : '/audio/ending/mp3/end_' + fileIndex + '.mp3';
    audio.play();

    el('page-game_over').addEventListener('pagebeforehide', function () {
        fadeOutAudio(audio, 500);
        setTimeout(function () { audio.pause(); }, 500);
    }, { once: true });
}


/* ── Data ──────────────────────────────────────── */

function getFields(callback) {
    if (AppStorage.fields) {
        callback();
    } else {
        adapter.DbTransfer.getOrderedFields({ isTestMode: false }, function (err, fields) {
            if (err) { alert('Error: ' + err); return; }
            AppStorage.fields = fields;
            callback();
        });
    }
}

function fillWithZero(zahl, length) {
    var tmp = '' + zahl;
    while (tmp.length < length) { tmp = '0' + tmp; }
    return tmp;
}

function getNvcStepColorClass(field) {
    var nvc_steps = AppStorage.getSetting('SETTING_DANCEFLOOR')
        ? { 1: 'bg-yellow', 2: 'bg-red',  3: 'bg-green', 4: 'bg-blue' }
        : { 1: 'bg-blue',   2: 'bg-red',  3: 'bg-green', 4: 'bg-yellow' };
    return nvc_steps[field.nvc_step] || 'bg-purple';
}


/* ── Game task ─────────────────────────────────── */

function getTask() {
    getFields(function () {
        if (AppStorage.isRandomEnabled() === true) {
            var field = AppStorage.fields[Math.floor(Math.random() * AppStorage.fields.length)];
            AppStorage.setCurrentField(field);
        }
        var currentPlayer = AppStorage.getCurrentPlayer();
        if (!currentPlayer) { window.location.replace('/'); return; }
        el('current-player').textContent = currentPlayer.name + ' ist dran';

        var currentField = AppStorage.getCurrentField();
        var args = {
            fieldId: currentField.id,
            excludedTasks: AppStorage.getPlayedTasks(),
            voices: AppStorage.getActiveVoices(),
            onlyNvcCompliant: AppStorage.getSetting('SETTING_NVCCONFORM'),
            playedSounds: AppStorage.getPlayedSounds()
        };

        adapter.DbTransfer.getTaskAndSound(args, function (err, data) {
            if (err) { alert('Error: ' + err); return; }

            var currentTask = data.task;
            AppStorage.addPlayedTask(currentTask._id);
            if (currentTask.resetPlayedTasks) { AppStorage.resetPlayedTasksForCurrentField(); }
            AppStorage.setCurrentTask(currentTask);

            var fieldTextEl   = el('field-text');
            var taskContentEl = el('task-content');

            if (currentField.foto === 0) {
                var content = currentTask.content1;
                var fname = currentField.name.toLowerCase();
                if (fname === 'w1') {
                    var steps = content.split('\n');
                    if (steps.length === 4) {
                        content = '<font color="#cde3f1">' + steps[0] + '</font>' +
                                  '<font color="#fed9e0">' + steps[1] + '</font>' +
                                  '<font color="#b8dc7c">' + steps[2] + '</font>' +
                                  '<font color="#ffff89">' + steps[3] + '</font>';
                    }
                } else if (currentTask.content2) {
                    if (fname === 'w6') {
                        content = '<font color="#0033FF">Die Aussage:</font><br>' + content +
                                  '<br><font color="#0033FF">Die Reaktion:<br></font>' + currentTask.content2 + '<br>';
                    } else if (fname === 'w11') {
                        content = '<font color="#0033FF">Die Nachricht:</font><br>' + content +
                                  '<br><font color="#0033FF">Die Reaktion:<br></font>' + currentTask.content2 + '<br>';
                    } else {
                        content += '<br/>' + currentTask.content2;
                    }
                }
                taskContentEl.innerHTML = content;
            } else {
                var imgName   = currentField.name.toLowerCase() + '_' + fillWithZero(currentTask.number, 3);
                var imgHeight = window.innerHeight / 3;
                taskContentEl.innerHTML = '<img id="task-img" src="img/' +
                    currentField.name.toLowerCase() + '/' + imgName + '.jpg" height="' + imgHeight + '"/>';
            }

            var colClass = getNvcStepColorClass(currentField);
            fieldTextEl.innerHTML = currentField.description;
            fieldTextEl.className = colClass;
            taskContentEl.className = colClass;

            var choiceList = el('choicelist');
            choiceList.innerHTML = '';
            currentTask.choices.forEach(function (choice) {
                var isCorrect = choice.is_correct ? 'is-correct' : '';
                var li = document.createElement('li');
                li.innerHTML = '<a id="choicebtn" class="bg-gray result-margin choice-btn ' + isCorrect + '">' + choice.content + '</a>';
                choiceList.appendChild(li);
            });

            document.querySelectorAll('.choice-btn').forEach(function (btn) {
                btn.addEventListener('click', function () {
                    var firstBtn = document.querySelector('.choice-btn');
                    if (firstBtn && firstBtn.dataset.disabled === 'true') { return; }

                    fadeIn(el('button-div'));
                    if (currentTask.solution_hint) { el('explanation-btn').style.display = 'inline-block'; }

                    var selected   = this;
                    var wasCorrect = selected.classList.contains('is-correct');
                    AppStorage.updateScoreForCurrentPlayer(wasCorrect);
                    playVoiceSound(data, wasCorrect);

                    var fieldDesc  = currentField.description;
                    var colClass2  = getNvcStepColorClass(currentField);
                    if (wasCorrect) {
                        fieldDesc = 'Hier stimmen wir überein.&nbsp;&nbsp;&nbsp;&nbsp;<img src="img/gruenerhaken.png" align="right"/><br/><br/>' + fieldDesc;
                    } else {
                        fieldDesc = 'Hier stimmen wir nicht überein.&nbsp;&nbsp;&nbsp;&nbsp;<img src="img/roteskreuz.png" align="right"/><br/><br/>' + fieldDesc;
                    }
                    fieldTextEl.innerHTML = fieldDesc;
                    fieldTextEl.className = colClass2;

                    document.querySelectorAll('.choice-btn').forEach(function (btn2) {
                        btn2.dataset.disabled = 'true';
                        btn2.id = 'disabledChoiceBtnLink';
                        if (btn2.classList.contains('is-correct')) {
                            btn2.classList.remove('bg-gray');
                            btn2.classList.add('bg-green-result');
                        } else if (btn2 === selected) {
                            btn2.classList.remove('bg-gray');
                            btn2.classList.add('bg-red-result');
                        }
                    });
                });
            });

            el('help-btn').style.display = 'inline-block';
            el('button-div').style.display = 'none';
            el('explanation-btn').style.display = 'none';
        });
    });
}


/* ── Videos ────────────────────────────────────── */

function renderVideoList(videoList) {
    var items = '';
    videoList.forEach(function (video) {
        items += '<a href="' + video.url + '" target="_blank" class="video-item">' +
            '<img src="img/video' + video.display_order + '.jpg"/>' +
            '<span>' + video.name + '</span>' +
            '</a>';
    });
    return '<div class="video-list">' + items + '</div>';
}

function initHelpVideo(fieldId) {
    adapter.DbTransfer.getVideosForField({ fieldId: fieldId }, function (err, data) {
        if (err) { alert('Error: ' + err); return; }
        el('help_video').innerHTML = renderVideoList(data);
    });
}

function initVideoList() {
    adapter.DbTransfer.getOrderedVideos({}, function (err, data) {
        if (err) { alert('Error: ' + err); return; }
        el('videos').innerHTML = renderVideoList(data);
    });
}


/* ── Field list ────────────────────────────────── */

function initFieldListPage() {
    getFields(function () {
        var fieldList = el('fieldlist');
        AppStorage.fields.forEach(function (field, i) {
            var colClass = getNvcStepColorClass(field);
            var li = document.createElement('li');
            li.innerHTML = '<a class="' + colClass + '" href="#page-task" id="field-btn' + i + '">' + field.title + '</a>';
            fieldList.appendChild(li);
            document.getElementById('field-btn' + i).addEventListener('click', function () {
                AppStorage.setCurrentField(field);
                getTask();
            });
        });
    });
}


/* ── Settings ──────────────────────────────────── */

function initSettings() {
    var addHandler = function (id, setting) {
        el(id).addEventListener('change', function () {
            store.set(setting, this.checked);
        });
    };
    addHandler('cbSettingSound',      'SETTING_SOUND');
    addHandler('cbSettingKlaus',      'SETTING_KLAUS');
    addHandler('cbSettingAntonia',    'SETTING_ANTONIA');
    addHandler('cbSettingSarina',     'SETTING_SARINA');
    addHandler('cbSettingNvcConform', 'SETTING_NVCCONFORM');
    addHandler('cbSettingPositive',   'SETTING_POSITIVE');
    addHandler('cbSettingDanceFloor', 'SETTING_DANCEFLOOR');
}

function loadSettings() {
    var load = function (id, setting) {
        el(id).checked = AppStorage.getSetting(setting);
    };
    load('cbSettingSound',      'SETTING_SOUND');
    load('cbSettingKlaus',      'SETTING_Klaus');
    load('cbSettingAntonia',    'SETTING_ANTONIA');
    load('cbSettingSarina',     'SETTING_SARINA');
    load('cbSettingNvcConform', 'SETTING_NVCCONFORM');
    load('cbSettingPositive',   'SETTING_POSITIVE');
    load('cbSettingDanceFloor', 'SETTING_DANCEFLOOR');
}


/* ── Task page ─────────────────────────────────── */

function initTaskPage() {
    el('task-continue-btn').addEventListener('click', function () {
        document.querySelectorAll('.choice-btn').forEach(function (btn) {
            btn.dataset.disabled = 'true';
            btn.removeAttribute('id');
        });
        if (AppStorage.isGameFinished()) {
            playEndMusic();
            el('task-continue-btn').setAttribute('href', '#page-game_over');
        }
        if (AppStorage.isRandomEnabled()) { getTask(); }
    });

    el('help-btn').addEventListener('click', function () {
        var currentField = AppStorage.getCurrentField();
        el('help_txt').innerHTML = currentField.help;
        initHelpVideo(currentField.id);
    });

    el('explanation-btn').addEventListener('click', function () {
        el('explanation_txt').innerHTML = AppStorage.getCurrentTask().solution_hint;
    });
}


/* ── Start button href ─────────────────────────── */

function initStartBtnLink() {
    var random = AppStorage.isRandomEnabled();
    var dest   = random ? '#page-task' : '#page-field_list';
    el('start-btn').setAttribute('href', dest);
    el('task-continue-btn').setAttribute('href', dest);
}


/* ── New game ──────────────────────────────────── */

function getPlayerNames() {
    var names = [];
    document.querySelectorAll('.playernameinput').forEach(function (input) {
        var name = input.value || input.getAttribute('placeholder');
        names.push(name);
    });
    return names;
}

function Player(name, totalTasks) {
    this.name       = name;
    this.score      = 0;
    this.totalTasks = totalTasks;
}

function savePlayerNames(playerNames) {
    var players = playerNames.map(function (name) { return new Player(name, 0); });
    store.set('KEY_PLAYERS', players);
}

function addPlayer(addRemoveButton) {
    var presentNames = getPlayerNames();
    var index        = presentNames.length;
    if (index > 3) { return; }

    var defaultNames = ['Antonia', 'Ben', 'Friederike', 'Jan'];
    var savedPlayers = AppStorage.getPlayers();
    if (savedPlayers) {
        var savedNames = savedPlayers.map(function (p) { return p.name; });
        defaultNames   = savedNames.concat(defaultNames);
    }

    var defaultName = '';
    defaultNames.some(function (name) {
        if (presentNames.indexOf(name) < 0) { defaultName = name; return true; }
    });

    var removeButton = addRemoveButton
        ? '<a class="nav-btn bg-red remove-player-btn" id="removeplayer-btn' + index + '"><i class="icon-remove"></i></a>'
        : '';

    var html = '<div class="divname">' +
        '<input type="text" class="playernameinput" name="name" id="name' + index + '" value placeholder=' + defaultName + '  />' +
        removeButton +
        '</div>';

    var playerDiv = el('playernames');
    playerDiv.insertAdjacentHTML('beforeend', html);

    if (addRemoveButton) {
        document.getElementById('removeplayer-btn' + index).addEventListener('click', function () {
            this.closest('.divname').remove();
        });
    }
}

function initNewGame() {
    addPlayer(false);
    el('start-btn').addEventListener('click', function () {
        AppStorage.setRandomEnabled(!el('cbManual').checked);
        AppStorage.resetPlayedSounds();
        AppStorage.resetAllPlayedTasks();
        AppStorage.startGame(getPlayerNames());
        var maxRounds = parseInt(el('select-runden').value, 10);
        AppStorage.setMaxNumberOfRounds(maxRounds);
        initStartBtnLink();
    });
    el('addplayer-btn').addEventListener('click', function () { addPlayer(true); });
}


/* ── Score ─────────────────────────────────────── */

function renderScoreCards(players) {
    var html = '';
    players.forEach(function (player) {
        var score  = player.score;
        var res    = player.totalTasks > 0 ? Math.round(score * 100 / player.totalTasks) : 100;
        var plural = score === 1 ? 'Punkt' : 'Punkte';
        html += '<div class="score-card">' +
            '<span class="score-name">' + player.name + '</span>' +
            '<span class="score-points">' + score + ' ' + plural + '</span>' +
            '<span class="score-pct">' + res + '%</span>' +
            '</div>';
    });
    return html;
}

function fillScore() {
    var players = store.get('KEY_PLAYERS');
    if (players === undefined) { window.mobileChangePage('/'); return; }
    el('score').innerHTML = renderScoreCards(players);
}


/* ── Game over ─────────────────────────────────── */

function initGameOverScore(players) {
    var imgNumber = AppStorage.getNextImageNameGameOver();
    var quote     = endGameQuotes[imgNumber];
    var txt =
        '<p class="gameover-title">Gut gespielt!</p>' +
        renderScoreCards(players) +
        '<div class="gameover-image">' +
            '<img src="img/end/end' + imgNumber + '.jpg" alt="' + quote + '" />' +
            '<blockquote class="gameover-quote">' + quote + '</blockquote>' +
        '</div>' +
        '<div class="gameover-buttons">' +
            '<a href="#page-task" id="replay-btn" class="bg-green menu-btn">Nochmal spielen</a>' +
            '<a href="#page-main_menu" class="bg-gray menu-btn">Hauptmenü</a>' +
        '</div>';
    el('finalscore').innerHTML = txt;
    el('finalscore').style.display = 'block';
    store.set('KEY_TOTAL_NUMBER_OF_TASKS', 0);
}

function hideGameOver() {
    el('finalscore').style.display = 'none';
}

function initGameOver() {
    var players = store.get('KEY_PLAYERS');
    if (players === undefined) { window.mobileChangePage('/'); return; }
    initGameOverScore(players);
    el('replay-btn').addEventListener('click', function () {
        var ps    = store.get('KEY_PLAYERS');
        var names = ps.map(function (p) { return p.name; });
        AppStorage.startGame(names);
        AppStorage.resetPlayedSounds();
        AppStorage.resetAllPlayedTasks();
        initStartBtnLink();
    });
}


/* ── Ask if new game ───────────────────────────── */

function initAskifnewgame() {
    el('ask-continue-btn').addEventListener('click', function () {
        if (AppStorage.isRandomEnabled()) { getTask(); }
    });
}

function showAskifnewgame() {
    var total   = store.get('KEY_TOTAL_NUMBER_OF_TASKS');
    var contBtn = el('ask-continue-btn');
    if (total && total > 0) {
        contBtn.style.display = 'inline-block';
        contBtn.setAttribute('href', AppStorage.isRandomEnabled() ? '#page-task' : '#page-field_list');
    } else {
        contBtn.style.display = 'none';
    }
}


/* ── Init ──────────────────────────────────────── */

var initApp = function () {
    var s = function (id, event, handler) {
        document.getElementById(id).addEventListener(event, handler);
    };
    s('page-settings',     'pagecreate', initSettings);
    s('page-settings',     'pageshow',   loadSettings);
    s('page-nvc_videos',   'pagecreate', initVideoList);
    s('page-field_list',   'pagecreate', initFieldListPage);
    s('page-task',         'pagecreate', initTaskPage);
    s('dialog-score',      'pageshow',   fillScore);
    s('page-new_game',     'pagecreate', initNewGame);
    s('page-game_over',    'pageshow',   initGameOver);
    s('page-game_over',    'pagehide',   hideGameOver);
    s('page-askifnewgame', 'pagecreate', initAskifnewgame);
    s('page-askifnewgame', 'pageshow',   showAskifnewgame);
};

/* exported initApp */


/* ── Storage ───────────────────────────────────── */

AppStorage = {
    fields: undefined,

    setCurrentTask:    function (task)  { store.set('KEY_CURRENT_TASK',  task);  },
    getCurrentTask:    function ()       { return store.get('KEY_CURRENT_TASK');  },
    setCurrentField:   function (field) { store.set('KEY_CURRENT_FIELD', field); },
    getCurrentField:   function ()       { return store.get('KEY_CURRENT_FIELD'); },

    startGame: function (playerNames) {
        savePlayerNames(playerNames);
        store.set('KEY_TOTAL_NUMBER_OF_TASKS', 0);
        if (AppStorage.isRandomEnabled()) { getTask(); }
    },

    updateScoreForCurrentPlayer: function (answerWasCorrect) {
        var players       = store.get('KEY_PLAYERS');
        var currentPlayer = players.shift();
        currentPlayer.totalTasks += 1;
        if (answerWasCorrect) { currentPlayer.score += 1; }
        players.push(currentPlayer);
        store.set('KEY_PLAYERS', players);
        store.set('KEY_TOTAL_NUMBER_OF_TASKS', store.get('KEY_TOTAL_NUMBER_OF_TASKS') + 1);
    },

    getPlayers:        function () { return store.get('KEY_PLAYERS'); },
    getCurrentPlayer:  function () { var p = store.get('KEY_PLAYERS'); return p ? p[0] : null; },

    setRandomEnabled:  function (isEnabled) { store.set('KEY_SELECT_FIELDS_MANUALLY', !isEnabled); },
    isRandomEnabled:   function ()           { return !store.get('KEY_SELECT_FIELDS_MANUALLY'); },

    getNumberOfRounds:    function ()    { return store.get('KEY_NUMBER_OF_ROUNDS'); },
    setMaxNumberOfRounds: function (max) { store.set('KEY_MAX_NUMBER_OF_ROUNDS', max); },

    isGameFinished: function () {
        var total     = store.get('KEY_TOTAL_NUMBER_OF_TASKS');
        var players   = store.get('KEY_PLAYERS').length;
        var maxRounds = store.get('KEY_MAX_NUMBER_OF_ROUNDS');
        return (maxRounds * players - total) === 0;
    },

    addPlayedTask: function (task) {
        var played    = store.get('KEY_PLAYED_TASKS');
        var fieldName = AppStorage.getCurrentField().name;
        var fieldTasks = played[fieldName] || [];
        fieldTasks.push(task);
        played[fieldName] = fieldTasks;
        store.set('KEY_PLAYED_TASKS', played);
    },

    getPlayedTasks: function () {
        var all       = store.get('KEY_PLAYED_TASKS');
        if (all === undefined) { return []; }
        var fieldName = AppStorage.getCurrentField().name;
        if (!all[fieldName]) { all[fieldName] = []; store.set('KEY_PLAYED_TASKS', all); }
        return all[fieldName];
    },

    resetPlayedTasksForCurrentField: function () {
        var played = store.get('KEY_PLAYED_TASKS');
        played[AppStorage.getCurrentField().name] = [];
        store.set('KEY_PLAYED_TASKS', played);
    },

    resetAllPlayedTasks: function () { store.set('KEY_PLAYED_TASKS', {}); },

    addPlayedSound: function (sound) {
        var sounds = store.get('KEY_PLAYED_SOUNDS') || [];
        sounds.push(sound);
        store.set('KEY_PLAYED_SOUNDS', sounds);
    },

    getPlayedSounds:  function () { return store.get('KEY_PLAYED_SOUNDS') || []; },
    resetPlayedSounds: function () { store.set('KEY_PLAYED_SOUNDS', []); },

    getSetting: function (key) {
        var value = store.get(key);
        return value === undefined ? defaults[key] : value;
    },

    getActiveVoices: function () {
        var voices = [];
        if (AppStorage.getSetting('SETTING_KLAUS'))    { voices.push('Klaus'); }
        if (AppStorage.getSetting('SETTING_ANTONIA'))  { voices.push('Antonia'); }
        if (AppStorage.getSetting('SETTING_SARINA'))   { voices.push('Sarina'); }
        return voices;
    },

    getNextImageNameGameOver: function () {
        var n     = 42;
        var index = store.get('KEY_IMAGES_GAME_OVER_INDEX');
        if (index === undefined || index === n) { index = 0; }
        index += 1;
        store.set('KEY_IMAGES_GAME_OVER_INDEX', index);
        return index;
    },

    getNextEndSoundIndex: function () {
        var n     = 8;
        var index = store.get('KEY_AUDIO_GAME_OVER_INDEX');
        if (index === undefined || index === n) { index = 0; }
        index += 1;
        store.set('KEY_AUDIO_GAME_OVER_INDEX', index);
        return index;
    }
};
var _makeTransferFunction = function (name) {
    return function (args, callback) {
        fetch('/ajax/' + name, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(args)
        })
        .then(function (res) {
            if (!res.ok) { throw new Error(res.statusText); }
            return res.json();
        })
        .then(function (data) { callback(null, data); })
        .catch(function (err) { callback(err.message); });
    };
};

var adapter = {
    DbTransfer: {
        getOrderedFields:   _makeTransferFunction('getOrderedFields'),
        getRandomTask:      _makeTransferFunction('getRandomTask'),
        getStaticText:      _makeTransferFunction('getStaticText'),
        getVideosForField:  _makeTransferFunction('getVideosForField'),
        getOrderedVideos:   _makeTransferFunction('getOrderedVideos'),
        getRandomSound:     _makeTransferFunction('getRandomSound'),
        getTaskAndSound:    _makeTransferFunction('getTaskAndSound')
    }
};

/* exported adapter */
